const immediatelyExecuteCommand = (trackingId, method, ...args) => {
	window[`yaCounter${trackingId}`][method](...args);
};

const deferExecuteCommand = (trackingId, ...args) => {
	document.addEventListener(`yacounter${trackingId}inited`, () => {
		immediatelyExecuteCommand(trackingId, ...args);
	});
};

export const executeCommand = (trackindId, method, ...args) => {
	if (typeof window === 'undefined') {
		return;
	}

	if (typeof window[`yaCounter${trackindId}`] === 'undefined') {
		deferExecuteCommand(trackindId, method, ...args);
	}
};


